      },
      "index": {
        "type": "number",
        "description": "Insertion position index (required). Specifies where the block should be inserted. Use 0 to insert at the beginning. Use get_feishu_document_blocks tool to understand document structure if unsure. For consecutive insertions, calculate next index as previous index + 1."
      },
      "blocks": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "blockType": {
              "type": "string",
              "description": "Block type (required). Supports: 'text', 'code', 'heading', 'list', as well as 'heading1' through 'heading9'. For headings, we recommend using 'heading' with level property, but 'heading1'-'heading9' are also supported."
            },
            "options": {
              "anyOf": [
                {
                  "type": "object",
